), corrected_predictions as (
  select distinct prediction_id from corrected_details
)
delete from public.prediction_details pd
using corrected_predictions cp
where pd.prediction_id = cp.prediction_id
  and not exists (
    select 1
    from corrected_details cd
    where cd.prediction_id = pd.prediction_id
      and cd.match_id = pd.match_id
  );

select public.recalculate_rankings();

commit;
